// Define a TreeNode class for the binary tree
class TreeNode {
    constructor(x) {
        this.val = x;  // The value of the node
        this.left = null;  // Pointer to the left child
        this.right = null;  // Pointer to the right child
    }
}

// Function to perform preorder traversal of a binary tree iteratively
function preorderTraversal(root) {
    let preorder = [];  // List to store the preorder traversal result

    // If the root is null, return an empty traversal result
    if (!root) {
        return preorder;
    }

    let stack = [root];  // Stack to store nodes during traversal

    // Perform iterative preorder traversal
    while (stack.length > 0) {
        let node = stack.pop();  // Get the current node from the top of the stack
        preorder.push(node.val);  // Add the node's value to the preorder result

        // Push the right child onto the stack if exists
        if (node.right) {
            stack.push(node.right);
        }

        // Push the left child onto the stack if exists
        if (node.left) {
            stack.push(node.left);
        }
    }

    // Return the preorder traversal result
    return preorder;
}

// Main function to handle input and output
function main() {
    // Creating a binary tree
    let root = new TreeNode(1);
    root.left = new TreeNode(2);
    root.right = new TreeNode(3);
    root.left.left = new TreeNode(4);
    root.left.right = new TreeNode(5);

    // Getting the preorder traversal
    let result = preorderTraversal(root);

    // Displaying the preorder traversal result
